class NotificationManager{constructor(){this.permission=Notification.permission;}async requestPermission(){if(!('Notification' in window)){return 'denied';}try{const permission=await Notification.requestPermission();this.permission=permission;return permission;}catch(error){return 'denied';}}send(title,options={}){if(this.permission==='granted'){if(navigator.serviceWorker&&navigator.serviceWorker.controller){navigator.serviceWorker.ready.then(registration=>{registration.showNotification(title,{icon: '/favicon.png',badge: '/favicon.png',...options});});}else{new Notification(title,{icon: '/favicon.png',...options});}}else{}}async subscribeToPush(){if(this.permission!=='granted')return null;return 'mock-push-subscription-id';}}window.Notifications=new NotificationManager();